nvm_version_greater() {
  command awk 'BEGIN {
    if (ARGV[1] == "" || ARGV[2] == "") exit(1)
    split(ARGV[1], a, /\./);
    split(ARGV[2], b, /\./);
    for (i=1; i<=3; i++) {
      if (a[i] && a[i] !~ /^[0-9]+$/) exit(2);
      if (b[i] && b[i] !~ /^[0-9]+$/) { exit(0); }
      if (a[i] < b[i]) exit(3);
      else if (a[i] > b[i]) exit(0);
    }
    exit(4)
  }' "${1#v}" "${2#v}"
}

nvm_version_greater_than_or_equal_to() {
  command awk 'BEGIN {
    if (ARGV[1] == "" || ARGV[2] == "") exit(1)
    split(ARGV[1], a, /\./);
    split(ARGV[2], b, /\./);
    for (i=1; i<=3; i++) {
      if (a[i] && a[i] !~ /^[0-9]+$/) exit(2);
      if (a[i] < b[i]) exit(3);
      else if (a[i] > b[i]) exit(0);
    }
    exit(0)
  }' "${1#v}" "${2#v}"
}

shellspec_call_before_evaluation_hooks() {
  [ $# -lt 2 ] && set -- "$1" 1
  eval "[ \"\$2\" -gt \"\$SHELLSPEC_BEFORE_$1_INDEX\" ] &&:" && return 0
  shellspec_call_hook "BEFORE_$1" "$2" || return $?
  shellspec_call_before_evaluation_hooks "$1" "$(($2 + 1))"
}

shellspec_readfile_zsh_concat() {
  [ -e "$2" ] || { unset "$1" ||:; return 0; }
  [ -s "$2" ] || { eval "$1=''"; return 0; }
  # shellcheck disable=SC3043
  local shellspec_readfile_line='' shellspec_readfile_data=''
  while IFS= read -r shellspec_readfile_line; do
    # shellcheck disable=SC3024
    shellspec_readfile_data+="${shellspec_readfile_line}${SHELLSPEC_LF}"
  done < "$2"
  # shellcheck disable=SC3024
  shellspec_readfile_data+="$shellspec_readfile_line"
  eval "$1=\"\$shellspec_readfile_data\""
}

finddirs_lssort() {
  ( cd "$1" || exit
    echo "."
    # shellcheck disable=SC2012,SC2153
    "$SHELLSPEC_LS" -R ${2:+-L} . | { export LC_ALL=C; "$SHELLSPEC_SORT"; } | {
      while IFS= read -r line; do
        case $line in (./*:) echo "${line%:}"; break; esac
      done
      while IFS= read -r line; do
        case $line in (./*:) echo "${line%:}"; continue; esac
        break
      done
    }
  )
}
